#include "frodo_sampler.h"
#include <stdint.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <unistd.h>
#if defined(__x86_64__)||defined(__i386__)
#include <x86intrin.h>
static unsigned long long ticks(void){return __rdtsc();}
#else
static unsigned long long ticks(void){struct timespec ts;clock_gettime(CLOCK_MONOTONIC,&ts);return (unsigned long long)ts.tv_sec*1000000000ull+ts.tv_nsec;}
#endif
#if defined(__GNUC__) || defined(__clang__)
static void barrier(void){__asm__ __volatile__("" ::: "memory");}
#else
static void barrier(void){}
#endif
static uint64_t rs=1;static uint32_t rnd(void){rs=rs*6364136223846793005ULL+1442695040888963407ULL;return(uint32_t)(rs>>32);}static void fill16(uint16_t*x,size_t n,uint64_t seed){rs=seed;for(size_t i=0;i<n;i++)x[i]=(uint16_t)rnd();}static void fill8(uint8_t*x,size_t n,uint64_t seed){rs=seed;for(size_t i=0;i<n;i++)x[i]=(uint8_t)rnd();}static size_t envsz(const char*n,size_t d){char*s=getenv(n);return(s&&*s)?strtoull(s,0,10):d;}static uint64_t cksum(const uint16_t*x,size_t n){uint64_t s=1469598103934665603ULL;for(size_t i=0;i<n;i++){s^=x[i];s*=1099511628211ULL;}return s;}
static inline uint16_t signv(uint16_t m,uint8_t s){return(uint16_t)(((uint16_t)(-(uint16_t)(s&1u))^m)+(s&1u));}
static uint16_t lookup_u16(uint16_t x,const uint16_t*t,size_t n){uint16_t m=0;for(size_t i=0;i<n;i++)m+=(uint16_t)(x>=t[i]);return m;}static uint16_t lookup_u8(uint8_t x,const uint8_t*t,size_t n){uint16_t m=0;for(size_t i=0;i<n;i++)m+=(uint16_t)(x>=t[i]);return m;}static uint16_t lookup_orig(uint16_t x,const uint16_t*t,size_t n){uint16_t m=0;for(size_t i=0;i<n;i++)m+=(uint16_t)(x>t[i]);return m;}
static int accept(const frodo_sampler_params*p,uint16_t z,uint16_t*c,uint8_t*s){unsigned b=p->sda_table->random_draw_bits;uint16_t q=(uint16_t)p->sda_table->denominator_u64;*c=(uint16_t)(z&((1u<<b)-1u));*s=(uint8_t)((z>>b)&1u);return *c<q;}
static void emit(const frodo_sampler_params*p,const char*comp,const char*impl,size_t n,int rep,unsigned long long cyc,double cpa,double cpo,double apo,size_t acc,size_t words,uint64_t sum,int rc){printf("Frodo,%s,sda-cdt,reference,%s,%s,%zu,%ld,%d,%llu,%.6f,%.6f,%.6f,%zu,%zu,%llu,%s\n",p->name,comp,impl,n,(long)getpid(),rep,cyc,cpa,cpo,apo,acc,words,(unsigned long long)sum,rc?"error":"ok");}
static void frontend(const frodo_sampler_params*p,const uint16_t*w,size_t wc,size_t n,int rep,int er){volatile uint64_t sink=0;size_t acc=0,pos=0;barrier();unsigned long long t0=ticks();while(acc<n&&pos<wc){uint16_t c;uint8_t s;int ok=accept(p,w[pos++],&c,&s);sink+=(uint64_t)(ok?c:0)+s;acc+=(size_t)ok;}barrier();unsigned long long t1=ticks();if(er)emit(p,"source-frontend","benchmark-only-source-frontend",n,rep,t1-t0,pos?((double)(t1-t0)/pos):0,n?((double)(t1-t0)/n):0,n?((double)pos/n):0,acc,pos,sink,acc<n);}
static void mapping(const frodo_sampler_params*p,frodo_sampler_kind k,const uint16_t*c,const uint8_t*s,uint16_t*out,size_t n,int rep,int er){barrier();unsigned long long t0=ticks();if(k==FRODO_SAMPLER_ORIGINAL_CDT){const uint16_t*t=p->original_table->thresholds;for(size_t i=0;i<n;i++)out[i]=signv(lookup_orig(c[i],t,p->original_table->threshold_count),s[i]);}else if(p->sda_table->value_type==SDAT_TYPE_U8){const uint8_t*t=p->sda_table->thresholds;for(size_t i=0;i<n;i++)out[i]=signv(lookup_u8((uint8_t)c[i],t,p->sda_table->threshold_count),s[i]);}else{const uint16_t*t=p->sda_table->thresholds;for(size_t i=0;i<n;i++)out[i]=signv(lookup_u16(c[i],t,p->sda_table->threshold_count),s[i]);}barrier();unsigned long long t1=ticks();if(er)emit(p,"cdt-mapping",k==FRODO_SAMPLER_ORIGINAL_CDT?"original-reference":"sda-word-reference",n,rep,t1-t0,0,n?((double)(t1-t0)/n):0,1,n,n,cksum(out,n),0);}
static void full(const frodo_sampler_params*p,frodo_sampler_kind k,const uint8_t*buf,size_t blen,const uint16_t*w,size_t wc,uint16_t*out,size_t n,int rep,int er){frodo_sampler_stats fs={0};if(k==FRODO_SAMPLER_ORIGINAL_CDT)memcpy(out,w,n*2);barrier();unsigned long long t0=ticks();int rc=frodo_sample_n_dispatch(k,FRODO_BACKEND_REFERENCE,k==FRODO_SAMPLER_ORIGINAL_CDT?FRODO_FRONTEND_ORIGINAL_WORD:FRODO_FRONTEND_WORD_ORIENTED,p->id,out,n,buf,blen,w,wc,0);barrier();unsigned long long t1=ticks();frodo_sample_n_dispatch(k,FRODO_BACKEND_REFERENCE,k==FRODO_SAMPLER_ORIGINAL_CDT?FRODO_FRONTEND_ORIGINAL_WORD:FRODO_FRONTEND_WORD_ORIENTED,p->id,out,n,buf,blen,w,wc,&fs);double apo=k==FRODO_SAMPLER_ORIGINAL_CDT?1.0:(n?(double)fs.stats.attempts/n:0);if(er)emit(p,"full-sampler-core",k==FRODO_SAMPLER_ORIGINAL_CDT?"original-reference":"sda-word-reference",n,rep,t1-t0,0,n?((double)(t1-t0)/n):0,apo,n,fs.stats.random_bytes/2,cksum(out,n),rc);}
static void one(const frodo_sampler_params*p,size_t n,int rep,int er){size_t wc=n*8+4096,blen=n*8+4096;uint16_t*w=malloc(wc*2),*c=malloc(n*2),*out=malloc(n*2);uint8_t*buf=malloc(blen),*sg=malloc(n);if(!w||!c||!out||!buf||!sg)exit(2);fill16(w,wc,9000+rep+31*p->id);fill8(buf,blen,8000+rep+29*p->id);for(size_t i=0,a=0;i<wc&&a<n;i++){uint16_t cc;uint8_t ss;if(accept(p,w[i],&cc,&ss)){c[a]=cc;sg[a++]=ss;}}frontend(p,w,wc,n,rep,er);mapping(p,FRODO_SAMPLER_ORIGINAL_CDT,w,sg,out,n,rep,er);mapping(p,FRODO_SAMPLER_SDA_CDT,c,sg,out,n,rep,er);full(p,FRODO_SAMPLER_ORIGINAL_CDT,buf,blen,w,wc,out,n,rep,er);full(p,FRODO_SAMPLER_SDA_CDT,buf,blen,w,wc,out,n,rep,er);free(w);free(c);free(out);free(buf);free(sg);} 
int main(void){size_t reps=envsz("FRODO_BENCH_REPETITIONS",31),warm=envsz("FRODO_BENCH_WARMUP",5),n=envsz("FRODO_BENCH_SAMPLE_COUNT",1048576);puts("scheme,parameter_set,sampler_kind,backend,component,implementation,sample_count,process_id,repetition,cycles_total,cycles_per_attempt,cycles_per_output,attempts_per_output,accepted_outputs,source_words,checksum,status");for(size_t r=0;r<warm;r++)one(frodo_get_sampler_params((frodo_param_id)(r%3)),n,-1,0);for(size_t r=0;r<reps;r++)for(int id=0;id<3;id++)one(frodo_get_sampler_params((frodo_param_id)((id+r)%3)),n,(int)r,1);return 0;}
